23: export class SyntaxRangeProvider implements RangeProvider {
24: 
25: 	readonly id = ID_SYNTAX_PROVIDER;
26: 
27: 	readonly disposables: DisposableStore;
28: 
29: 	constructor(
30: 		private readonly editorModel: ITextModel,
31: 		private readonly providers: FoldingRangeProvider[],
32: 		readonly handleFoldingRangesChange: () => void,
33: 		private readonly foldingRangesLimit: FoldingLimitReporter,
34: 		private readonly fallbackRangeProvider: RangeProvider | undefined // used when all providers return null
35: 	) {
36: 		this.disposables = new DisposableStore();
37: 		if (fallbackRangeProvider) {
38: 			this.disposables.add(fallbackRangeProvider);
39: 		}
40: 
41: 		for (const provider of providers) {
42: 			if (typeof provider.onDidChange === 'function') {
43: 				this.disposables.add(provider.onDidChange(handleFoldingRangesChange));
44: 			}
45: 		}
46: 	}
47: 
48: 	compute(cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
49: 		return collectSyntaxRanges(this.providers, this.editorModel, cancellationToken).then(ranges => {
50: 			if (ranges) {
51: 				const res = sanitizeRanges(ranges, this.foldingRangesLimit);
52: 				return res;
53: 			}
54: 			return this.fallbackRangeProvider?.compute(cancellationToken) ?? null;
55: 		});
56: 	}
57: 
58: 	dispose() {
59: 		this.disposables.dispose();
60: 	}
61: }
