import { ITextModel } from '../../../common/model.js';

export interface NamedRange {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

export interface NamedRegionProvider {
	getNamedRegions(model: ITextModel): NamedRange[];
}

/**
 * Extracts named regions from #region and #endregion markers in the code.
 * Supports patterns like:
 * // #region MyRegionName
 * ...code...
 * // #endregion
 */
export function getNamedRegions(model: ITextModel): NamedRange[] {
	const regions: NamedRange[] = [];
	const lineCount = model.getLineCount();
	const regionStack: Array<{ name: string; startLineNumber: number }> = [];

	// Pattern to match #region markers with optional name
	const regionStartPattern = /#region\s*(.*)$/;
	const regionEndPattern = /#endregion/;

	for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
		const line = model.getLineContent(lineNumber);

		const startMatch = line.match(regionStartPattern);
		if (startMatch) {
			const name = startMatch[1].trim() || `Region ${lineNumber}`;
			regionStack.push({ name, startLineNumber: lineNumber });
			continue;
		}

		const endMatch = line.match(regionEndPattern);
		if (endMatch && regionStack.length > 0) {
			const region = regionStack.pop()!;
			regions.push({
				name: region.name,
				startLineNumber: region.startLineNumber,
				endLineNumber: lineNumber
			});
		}
	}

	return regions;
}

