/** Action to go to a named region using quick pick */
class GoToNamedRegion extends EditorAction {

	constructor() {
		super({
			id: 'editor.action.goToNamedRegion',
			label: nls.localize2('goToNamedRegion.label', "Go to Named Region"),
			alias: 'Go to Named Region',
			precondition: CONTEXT_FOLDING_ENABLED,
			kbOpts: {
				kbExpr: EditorContextKeys.editorTextFocus,
				primary: KeyMod.CtrlCmd | KeyMod.Shift | KeyCode.KeyR,
				weight: KeybindingWeight.EditorContrib
			}
		});
	}

	async run(accessor: ServicesAccessor, editor: ICodeEditor): Promise<void> {
		const quickInputService = accessor.get(IQuickInputService);
		const model = editor.getModel();

		if (!model) {
			return;
		}

		try {
			const regions = getNamedRegions(model);

			if (!regions || regions.length === 0) {
				quickInputService.open({
					placeHolder: nls.localize('goToNamedRegion.noRegions', 'No named regions found in this file')
				});
				return;
			}

			const picks = regions.map(region => ({
				label: region.name,
				description: `Line ${region.startLineNumber}`,
				region: region
			}));

			const selectedPick = await quickInputService.pick(picks, {
				placeHolder: nls.localize('goToNamedRegion.placeholder', 'Select a named region to go to'),
				matchOnDescription: true
			});

			if (selectedPick && selectedPick.region) {
				const { startLineNumber } = selectedPick.region;
				editor.setSelection({
					startLineNumber: startLineNumber,
					startColumn: 1,
					endLineNumber: startLineNumber,
					endColumn: 1
				});
				editor.revealPositionInCenterIfOutsideViewport(
					{ lineNumber: startLineNumber, column: 1 },
					ScrollType.Smooth
				);
			}
		} catch (error) {
			onUnexpectedError(error);
		}
	}
}
```

