/*---------------------------------------------------------------------------------------------
 *  Copyright (c) Microsoft Corporation. All rights reserved.
 *  Licensed under the MIT License. See License.txt in the project root for license information.
 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { getNamedRegions, NamedRange } from '../../browser/namedRangeProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detects simple named regions', () => {
		const lines = [
			'// #region MyRegion',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MyRegion');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Detects multiple named regions', () => {
		const lines = [
			'// #region First',
			'const a = 1;',
			'// #endregion',
			'',
			'// #region Second',
			'const b = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'First');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);
		assert.strictEqual(regions[1].name, 'Second');
		assert.strictEqual(regions[1].startLineNumber, 5);
		assert.strictEqual(regions[1].endLineNumber, 7);

		model.dispose();
	});

	test('Extracts region name from comment', () => {
		const lines = [
			'// #region My Custom Region Name',
			'code here',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'My Custom Region Name');

		model.dispose();
	});

	test('Handles regions with extra whitespace', () => {
		const lines = [
			'//   #region   SpacedName   ',
			'code',
			'//   #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'SpacedName');

		model.dispose();
	});

	test('Ignores unmatched endregion markers', () => {
		const lines = [
			'code',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Returns empty array when no regions exist', () => {
		const lines = [
			'const x = 1;',
			'const y = 2;'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Handles nested regions (only counts matched pairs)', () => {
		const lines = [
			'// #region Outer',
			'// #region Inner',
			'code',
			'// #endregion',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Outer');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 5);
		assert.strictEqual(regions[1].name, 'Inner');
		assert.strictEqual(regions[1].startLineNumber, 2);
		assert.strictEqual(regions[1].endLineNumber, 4);

		model.dispose();
	});

	test('Handles different comment styles', () => {
		const lines = [
			'/* #region Block */',
			'const x = 1;',
			'/* #endregion */'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Block');

		model.dispose();
	});

	test('Handles hash regions in block comments', () => {
		const lines = [
			'/*',
			' * #region Description',
			' */',
			'code',
			'/*',
			' * #endregion',
			' */'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Description');

		model.dispose();
	});

	test('Returns regions in order', () => {
		const lines = [
			'// #region Alpha',
			'code1',
			'// #endregion',
			'// #region Beta',
			'code2',
			'// #endregion',
			'// #region Gamma',
			'code3',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 3);
		assert.strictEqual(regions[0].name, 'Alpha');
		assert.strictEqual(regions[1].name, 'Beta');
		assert.strictEqual(regions[2].name, 'Gamma');

		model.dispose();
	});

	test('Preserves exact region names', () => {
		const lines = [
			'// #region camelCaseRegion',
			'code',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions[0].name, 'camelCaseRegion');

		model.dispose();
	});

	test('NamedRange interface has correct properties', () => {
		const lines = [
			'// #region TestRegion',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		const region = regions[0];

		// Verify all required properties exist
		assert('name' in region);
		assert('startLineNumber' in region);
		assert('endLineNumber' in region);

		// Verify types
		assert(typeof region.name === 'string');
		assert(typeof region.startLineNumber === 'number');
		assert(typeof region.endLineNumber === 'number');

		model.dispose();
	});
});

